export const INDEX_HTML = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"UTF-8\" />\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n  <title>LabBridge v2 — PC Terminal</title>\n  <link rel=\"manifest\" href=\"/manifest.json\">\n  <meta name=\"apple-mobile-web-app-capable\" content=\"yes\">\n  <meta name=\"apple-mobile-web-app-status-bar-style\" content=\"black-translucent\">\n  <meta name=\"theme-color\" content=\"#000000\">\n  <script src=\"qr.min.js\"></script>\n  <script src=\"jsQR.min.js\"></script>\n  <style>\n    :root {\n      --bg:           #000000;\n      --surface:      #080810;\n      --surface-2:    #0D0D18;\n      --border:       rgba(255, 255, 255, 0.06);\n      --border-hover: rgba(255, 255, 255, 0.12);\n      --primary:      #6C63FF;\n      --primary-dim:  rgba(108, 99, 255, 0.12);\n      --green:        #39FF14;\n      --green-dim:    rgba(57, 255, 20, 0.08);\n      --red:          #EF4444;\n      --red-dim:      rgba(239, 68, 68, 0.08);\n      --text:         #FFFFFF;\n      --text-2:       rgba(255, 255, 255, 0.5);\n      --text-3:       rgba(255, 255, 255, 0.25);\n      --mono:         'SF Mono', 'Fira Code', 'Cascadia Code', ui-monospace, monospace;\n      --sans:         -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;\n    }\n\n    * {\n      box-sizing: border-box;\n      margin: 0;\n      padding: 0;\n    }\n\n    body {\n      background: var(--bg);\n      color: var(--text);\n      min-height: 100vh;\n      display: flex;\n      align-items: center;\n      justify-content: center;\n      padding: 24px;\n      font-family: var(--sans);\n      background-image: radial-gradient(\n        ellipse 80% 40% at 50% -10%,\n        rgba(108, 99, 255, 0.10) 0%,\n        transparent 70%\n      );\n    }\n\n    .container {\n      width: 100%;\n      max-width: 560px;\n      display: flex;\n      flex-direction: column;\n      background: var(--surface);\n      border: 1px solid var(--border);\n      border-radius: 16px;\n      padding: 28px;\n      box-shadow: 0 0 0 1px rgba(255,255,255,0.03),\n                  0 32px 64px rgba(0,0,0,0.9);\n    }\n\n    #pc-mode-container, #phone-mode-container {\n      display: flex;\n      flex-direction: column;\n      width: 100%;\n    }\n\n    /* Header */\n    header {\n      display: flex;\n      justify-content: space-between;\n      align-items: center;\n      margin-bottom: 28px;\n      padding-bottom: 20px;\n      border-bottom: 1px solid var(--border);\n      width: 100%;\n      flex-shrink: 0;\n    }\n\n    .brand {\n      display: flex;\n      align-items: center;\n      gap: 12px;\n    }\n\n    .brand img {\n      width: 32px;\n      height: 32px;\n      border-radius: 8px;\n      border: 1px solid var(--border);\n    }\n\n    .brand-name {\n      font-family: var(--mono);\n      font-size: 15px;\n      font-weight: 700;\n      color: var(--text);\n      letter-spacing: -0.3px;\n    }\n\n    .brand-sub {\n      font-family: var(--mono);\n      font-size: 10px;\n      color: var(--text-3);\n      letter-spacing: 0.5px;\n      margin-top: 2px;\n    }\n\n    .status-pill {\n      display: flex;\n      align-items: center;\n      gap: 8px;\n      padding: 6px 10px;\n      border-radius: 9999px;\n      border: 1px solid var(--border);\n      background: transparent;\n      font-family: var(--mono);\n      font-size: 12px;\n      color: var(--text-2);\n    }\n\n    .status-dot {\n      width: 6px;\n      height: 6px;\n      border-radius: 50%;\n      background: var(--text-3);\n      flex-shrink: 0;\n    }\n\n    .status-dot.active {\n      background: var(--green);\n      box-shadow: 0 0 8px var(--green);\n    }\n\n    .btn-disconnect {\n      background: transparent;\n      border: none;\n      color: var(--red);\n      font-family: var(--mono);\n      font-size: 11px;\n      cursor: pointer;\n      padding: 0;\n      opacity: 0.7;\n    }\n\n    .btn-disconnect:hover { opacity: 1; }\n\n    /* Phase 1: Waiting (QR Screen) */\n    #phase-waiting {\n      display: flex;\n      flex-direction: column;\n      width: 100%;\n    }\n\n    .phase-label {\n      font-family: var(--mono);\n      font-size: 10px;\n      font-weight: 600;\n      letter-spacing: 2px;\n      color: var(--text-3);\n      text-align: center;\n      margin-bottom: 20px;\n    }\n\n    .qr-wrap {\n      display: flex;\n      justify-content: center;\n      margin-bottom: 24px;\n    }\n\n    .qr-box {\n      background: #fff;\n      padding: 14px;\n      border-radius: 12px;\n      position: relative;\n      display: inline-flex;\n      align-items: center;\n      justify-content: center;\n      box-shadow: 0 0 0 1px rgba(255,255,255,0.08),\n                  0 8px 32px rgba(108,99,255,0.15);\n    }\n\n    #qrcode {\n      width: 200px;\n      height: 200px;\n      display: flex;\n      align-items: center;\n      justify-content: center;\n    }\n\n    #qrcode img, #qrcode canvas {\n      display: block;\n      max-width: 100%;\n      max-height: 100%;\n    }\n\n    .qr-expired-overlay {\n      display: none;\n      position: absolute;\n      inset: 0;\n      background: rgba(255,255,255,0.95);\n      border-radius: 10px;\n      flex-direction: column;\n      align-items: center;\n      justify-content: center;\n      gap: 8px;\n      backdrop-filter: blur(4px);\n      z-index: 10;\n    }\n\n    .expired-icon {\n      font-size: 28px;\n      color: #000;\n    }\n\n    .expired-text {\n      font-family: var(--mono);\n      font-size: 13px;\n      font-weight: 700;\n      color: #000;\n    }\n\n    .btn-refresh-qr {\n      background: #6C63FF;\n      color: #fff;\n      border: none;\n      padding: 8px 16px;\n      border-radius: 6px;\n      font-family: var(--mono);\n      font-size: 12px;\n      font-weight: 600;\n      cursor: pointer;\n    }\n\n    /* Steps */\n    .steps {\n      display: flex;\n      flex-direction: column;\n      gap: 10px;\n      margin-bottom: 20px;\n      padding: 0 4px;\n    }\n\n    .step {\n      display: flex;\n      align-items: baseline;\n      gap: 12px;\n    }\n\n    .step-num {\n      font-family: var(--mono);\n      font-size: 11px;\n      font-weight: 700;\n      color: var(--primary);\n      flex-shrink: 0;\n      width: 20px;\n    }\n\n    .step-text {\n      font-size: 13px;\n      color: var(--text-2);\n      line-height: 1.4;\n    }\n\n    /* Session meta */\n    .session-meta {\n      display: flex;\n      align-items: center;\n      justify-content: space-between;\n      padding-top: 16px;\n      border-top: 1px solid var(--border);\n      font-family: var(--mono);\n      font-size: 11px;\n      color: var(--text-3);\n    }\n\n    .mono-accent {\n      font-family: var(--mono);\n      color: var(--primary);\n      font-weight: 600;\n    }\n\n    .btn-text {\n      background: transparent;\n      border: none;\n      color: var(--text-3);\n      font-family: var(--mono);\n      font-size: 11px;\n      cursor: pointer;\n      padding: 0;\n    }\n\n    .btn-text:hover { color: var(--text-2); }\n\n    /* Phase 2: Paired */\n    #phase-paired {\n      display: none;\n      flex-direction: column;\n      gap: 16px;\n      width: 100%;\n    }\n\n    #received-files-section {\n      padding: 14px 16px;\n      background: var(--primary-dim);\n      border: 1px solid rgba(108,99,255,0.2);\n      border-radius: 10px;\n    }\n\n    .folder-section {\n      padding: 14px 16px;\n      background: var(--surface-2);\n      border: 1px solid var(--border);\n      border-radius: 10px;\n    }\n\n    .section-label {\n      font-family: var(--mono);\n      font-size: 10px;\n      font-weight: 600;\n      letter-spacing: 1.5px;\n      color: var(--text-3);\n      text-transform: uppercase;\n      margin-bottom: 10px;\n    }\n\n    .breadcrumb {\n      display: flex;\n      align-items: center;\n      flex-wrap: wrap;\n      gap: 4px;\n      font-family: var(--mono);\n      font-size: 12px;\n      color: var(--text-3);\n      margin-bottom: 12px;\n      padding: 0;\n      background: transparent;\n      border: none;\n      border-radius: 0;\n    }\n\n    .breadcrumb-item {\n      color: var(--text-2);\n      cursor: pointer;\n      font-weight: 500;\n      transition: color 0.15s;\n    }\n\n    .breadcrumb-item:hover { color: var(--primary); }\n\n    .breadcrumb-sep {\n      color: var(--text-3);\n      font-size: 10px;\n    }\n\n    .folder-grid {\n      display: flex;\n      flex-wrap: wrap;\n      gap: 8px;\n      min-height: 40px;\n    }\n\n    .folder-btn {\n      background: transparent;\n      border: 1px solid var(--border);\n      color: var(--text-2);\n      padding: 7px 12px;\n      border-radius: 6px;\n      font-size: 12px;\n      font-family: var(--mono);\n      cursor: pointer;\n      transition: all 0.15s;\n      display: flex;\n      align-items: center;\n      gap: 6px;\n    }\n\n    .folder-btn:hover {\n      border-color: var(--border-hover);\n      color: var(--text);\n      background: rgba(255,255,255,0.03);\n    }\n\n    .folder-btn.active {\n      border-color: rgba(108,99,255,0.4);\n      background: var(--primary-dim);\n      color: var(--primary);\n    }\n\n    .dropzone {\n      border: 1px dashed rgba(255,255,255,0.1);\n      border-radius: 10px;\n      padding: 40px 20px;\n      text-align: center;\n      cursor: pointer;\n      transition: all 0.2s;\n      position: relative;\n      background: transparent;\n    }\n\n    .dropzone:hover,\n    .dropzone.dragover {\n      border-color: rgba(108,99,255,0.4);\n      background: var(--primary-dim);\n    }\n\n    .dropzone p {\n      font-family: var(--mono);\n      font-size: 13px;\n      font-weight: 600;\n      color: var(--text);\n      margin-bottom: 6px;\n      letter-spacing: 0.3px;\n    }\n\n    .dropzone span {\n      font-size: 12px;\n      color: var(--text-3);\n    }\n\n    .dropzone input[type=\"file\"] {\n      position: absolute;\n      inset: 0;\n      opacity: 0;\n      cursor: pointer;\n      width: 100%;\n      height: 100%;\n    }\n\n    .dropzone-icon {\n      font-size: 20px;\n      color: var(--text-3);\n      margin-bottom: 10px;\n      font-family: var(--mono);\n    }\n\n    /* Phase 3: Transferring */\n    #phase-transferring {\n      display: none;\n      flex-direction: column;\n      gap: 14px;\n      width: 100%;\n    }\n\n    .transfer-info {\n      display: flex;\n      justify-content: space-between;\n      align-items: baseline;\n      font-family: var(--mono);\n      font-size: 13px;\n    }\n\n    #transfer-filename { color: var(--text); font-weight: 600; }\n    #transfer-size { font-size: 11px; color: var(--text-3); margin-top: 3px; font-family: var(--mono); }\n    #transfer-pct { color: var(--primary); font-weight: 700; }\n\n    .progress-track {\n      width: 100%;\n      height: 2px;\n      background: rgba(255,255,255,0.06);\n      border-radius: 2px;\n      overflow: hidden;\n    }\n\n    .progress-fill {\n      height: 100%;\n      background: var(--primary);\n      width: 0%;\n      transition: width 0.1s linear;\n      box-shadow: 0 0 8px var(--primary);\n    }\n\n    .btn-cancel {\n      background: transparent;\n      border: none;\n      color: var(--text-3);\n      font-family: var(--mono);\n      font-size: 11px;\n      cursor: pointer;\n      padding: 0;\n      align-self: flex-start;\n      letter-spacing: 0.5px;\n    }\n\n    .btn-cancel:hover { color: var(--red); }\n\n    /* Phase 4: Done */\n    #phase-done {\n      display: none;\n      flex-direction: column;\n      align-items: center;\n      text-align: center;\n      gap: 16px;\n      padding: 20px 0;\n      width: 100%;\n    }\n\n    .done-icon {\n      width: 48px;\n      height: 48px;\n      border-radius: 50%;\n      background: var(--green-dim);\n      border: 1px solid rgba(57,255,20,0.2);\n      display: flex;\n      align-items: center;\n      justify-content: center;\n      font-family: var(--mono);\n      font-size: 20px;\n      color: var(--green);\n    }\n\n    #done-message {\n      font-family: var(--mono);\n      font-size: 14px;\n      font-weight: 700;\n      color: var(--text);\n      letter-spacing: -0.3px;\n    }\n\n    #done-subtext {\n      font-size: 12px;\n      color: var(--text-3);\n      margin-top: 4px;\n      font-family: var(--mono);\n    }\n\n    .btn-reset {\n      background: var(--primary-dim);\n      border: 1px solid rgba(108,99,255,0.3);\n      color: var(--primary);\n      padding: 10px 20px;\n      border-radius: 8px;\n      font-size: 13px;\n      font-family: var(--mono);\n      font-weight: 600;\n      cursor: pointer;\n      transition: all 0.15s;\n    }\n\n    .btn-reset:hover {\n      background: rgba(108,99,255,0.2);\n    }\n\n    /* Phone mode container adjustments inside index.html */\n    #phone-mode-container.container {\n      max-width: none;\n      border-radius: 0;\n      border: none;\n      background: var(--surface);\n      box-shadow: none;\n      padding: 20px;\n    }\n\n    #phone-mode-container input[type=\"text\"] {\n      width: 100%;\n      background: transparent;\n      border: 1px solid var(--border);\n      border-radius: 8px;\n      padding: 12px 14px;\n      color: var(--text);\n      font-family: var(--mono);\n      font-size: 14px;\n      outline: none;\n      transition: border-color 0.15s;\n    }\n    #phone-mode-container input[type=\"text\"]:focus { border-color: rgba(108,99,255,0.5); }\n\n    #phone-mode-container button {\n      width: 100%;\n      background: var(--primary);\n      color: #fff;\n      border: none;\n      border-radius: 8px;\n      padding: 14px;\n      font-family: var(--mono);\n      font-size: 13px;\n      font-weight: 700;\n      cursor: pointer;\n      letter-spacing: 0.3px;\n      transition: opacity 0.15s;\n    }\n    #phone-mode-container button:active { opacity: 0.8; }\n    #phone-mode-container button.secondary {\n      background: transparent;\n      border: 1px solid var(--border);\n      color: var(--text-2);\n    }\n  </style>\n</head>\n<body>\n  <!-- PC Mode Container -->\n  <div id=\"pc-mode-container\" class=\"container\">\n    <header>\n      <!-- Left: brand -->\n      <div class=\"brand\">\n        <img src=\"logo.png\" alt=\"LabBridge Logo\" />\n        <div>\n          <div class=\"brand-name\">LabBridge</div>\n          <div class=\"brand-sub\">[ E2E ENCRYPTED · ZERO CLOUD ]</div>\n        </div>\n      </div>\n      <!-- Right: status pill -->\n      <div class=\"status-pill\">\n        <div id=\"status-dot\" class=\"status-dot\"></div>\n        <span id=\"status-text\">Disconnected</span>\n        <button id=\"btn-disconnect\" class=\"btn-disconnect\" style=\"display:none;\" onclick=\"disconnectSession()\">disconnect</button>\n      </div>\n    </header>\n\n    <!-- Phase 1: Waiting -->\n    <div id=\"phase-waiting\">\n      <div class=\"phase-label\">WAITING FOR DEVICE</div>\n\n      <div class=\"qr-wrap\">\n        <div class=\"qr-box\">\n          <div id=\"qrcode\"></div>\n          <div id=\"qr-expired-overlay\" class=\"qr-expired-overlay\">\n            <div class=\"expired-icon\">↻</div>\n            <div class=\"expired-text\">QR Expired</div>\n            <button onclick=\"createSession()\" class=\"btn-refresh-qr\">Refresh</button>\n          </div>\n        </div>\n      </div>\n\n      <div class=\"steps\">\n        <div class=\"step\">\n          <span class=\"step-num\">01</span>\n          <span class=\"step-text\">Open LabBridge app or iPhone camera</span>\n        </div>\n        <div class=\"step\">\n          <span class=\"step-num\">02</span>\n          <span class=\"step-text\">Point at this QR code</span>\n        </div>\n        <div class=\"step\">\n          <span class=\"step-num\">03</span>\n          <span class=\"step-text\">Connected — drag files below</span>\n        </div>\n      </div>\n\n      <div class=\"session-meta\">\n        <span>session <span id=\"display-session-id\" class=\"mono-accent\">---</span></span>\n        <span>expires <span id=\"timer-sec\" class=\"mono-accent\">240s</span></span>\n        <button id=\"btn-refresh-waiting\" onclick=\"createSession()\" class=\"btn-text\">↻ refresh</button>\n      </div>\n    </div>\n\n    <!-- Phase 2: Paired -->\n    <div id=\"phase-paired\">\n      <div id=\"received-files-section\" style=\"display:none;\">\n        <div class=\"section-label\">RECEIVED FROM MOBILE DEVICE</div>\n        <div id=\"received-files-list\"></div>\n      </div>\n\n      <div class=\"folder-section\">\n        <div class=\"section-label\">TARGET FOLDER ON PHONE</div>\n        <div id=\"breadcrumb\" class=\"breadcrumb\">\n          <span class=\"breadcrumb-item\" onclick=\"navigateRoot()\">Root</span>\n        </div>\n        <div id=\"folder-grid\" class=\"folder-grid\"></div>\n      </div>\n\n      <div id=\"shortcut-mode-hint\" style=\"display:none; padding: 12px 16px; background: var(--primary-dim); border: 1px solid rgba(108,99,255,0.3); border-radius: 10px; font-size: 13px; color: var(--primary); font-family: var(--mono);\">\n        iPhone Shortcut mode active — drop a file below and your iPhone will receive it immediately via polling\n      </div>\n\n      <div id=\"dropzone\" class=\"dropzone\">\n        <input type=\"file\" id=\"file-input\" multiple />\n        <div class=\"dropzone-icon\">↑</div>\n        <p>Drop files to transfer</p>\n        <span id=\"queue-status\">E2E encrypted · saves directly to phone folder</span>\n      </div>\n    </div>\n\n    <!-- Phase 3: Transferring -->\n    <div id=\"phase-transferring\">\n      <div class=\"transfer-info\">\n        <span id=\"transfer-filename\">file.pdf</span>\n        <span id=\"transfer-pct\">0%</span>\n      </div>\n      <div id=\"transfer-size\">0 KB</div>\n      <progress id=\"transfer-progress\" value=\"0\" max=\"100\" style=\"display:none;\"></progress>\n      <div class=\"progress-track\">\n        <div class=\"progress-fill\" id=\"progress-fill-bar\"></div>\n      </div>\n      <button class=\"btn-cancel\" onclick=\"cancelTransfer()\">cancel transfer</button>\n    </div>\n\n    <!-- Phase 4: Done -->\n    <div id=\"phase-done\">\n      <div class=\"done-icon\">✓</div>\n      <div>\n        <p id=\"done-message\">TRANSFER COMPLETED!</p>\n        <p id=\"done-subtext\">Saved to phone</p>\n      </div>\n      <button class=\"btn-reset\" onclick=\"resetToPaired()\">Send Another File</button>\n    </div>\n  </div>\n\n  <!-- Phone Mode Container -->\n  <div id=\"phone-mode-container\" class=\"container\" style=\"display: none;\">\n    <header>\n      <div class=\"brand\">\n        <img src=\"logo.png\" alt=\"LabBridge Logo\" style=\"width: 28px; height: 28px; border-radius: 6px; border: 1px solid var(--border);\" />\n        <div>\n          <div class=\"brand-name\">LabBridge</div>\n        </div>\n      </div>\n      <div class=\"status-pill\">\n        <div id=\"phone-status-dot\" class=\"status-dot\"></div>\n        <span id=\"phone-status-text\">Disconnected</span>\n      </div>\n    </header>\n\n    <!-- Screen 1: Scanner -->\n    <div id=\"phone-screen-scanner\" style=\"display: flex; flex-direction: column; gap: 16px;\">\n      <p style=\"font-size: 13px; color: var(--text-2); text-align: center;\">Point camera at PC screen QR code to pair</p>\n      <div style=\"background: #000; border-radius: 12px; overflow: hidden; position: relative; min-height: 260px; display: flex; align-items: center; justify-content: center; border: 1px solid var(--border);\">\n        <video id=\"phone-video\" playsinline autoplay muted style=\"width: 100%; height: auto; display: block;\"></video>\n        <div id=\"phone-camera-msg\" style=\"position: absolute; color: var(--text-3); font-size: 13px; text-align: center; padding: 20px; font-family: var(--mono);\">Requesting camera access...</div>\n      </div>\n      <div style=\"display: flex; flex-direction: column; gap: 10px; margin-top: 8px;\">\n        <input type=\"text\" id=\"phone-manual-id\" placeholder=\"Or enter 12-char ID manually\" maxlength=\"12\" />\n        <button onclick=\"phoneConnectManual()\">Connect</button>\n      </div>\n    </div>\n\n    <!-- Screen 2: Connected -->\n    <div id=\"phone-screen-connected\" style=\"display: none; flex-direction: column; gap: 16px;\">\n      <div class=\"folder-section\">\n        <p style=\"font-size: 13px; color: var(--text); font-weight: 700; font-family: var(--mono);\">CONNECTED TO PC TERMINAL</p>\n        <p id=\"phone-session-info\" style=\"font-size: 12px; color: var(--primary); margin-top: 4px; font-family: var(--mono);\">Session ID: ---</p>\n      </div>\n\n      <!-- Send Dropzone -->\n      <div id=\"phone-dropzone\" class=\"dropzone\">\n        <input type=\"file\" id=\"phone-file-input\" multiple onchange=\"phoneHandleFilesSelected(event)\" />\n        <div style=\"font-family: var(--mono); font-size: 18px; color: var(--text-3); margin-bottom: 8px;\">↑</div>\n        <div style=\"font-family: var(--mono); font-size: 13px; font-weight: 700; color: var(--text);\">Tap to send files to PC</div>\n        <div style=\"font-size: 12px; color: var(--text-3); margin-top: 4px;\">Photos · Files · iCloud Drive</div>\n      </div>\n\n      <!-- Active Transfer Progress -->\n      <div id=\"phone-transfer-area\" style=\"display: none; flex-direction: column; gap: 14px; padding: 18px; background: var(--surface); border: 1px solid var(--border); border-radius: 12px;\">\n        <div style=\"display: flex; justify-content: space-between; font-size: 13px; font-weight: 700; font-family: var(--mono);\">\n          <span id=\"phone-transfer-title\" style=\"color: #FFF;\">Transferring...</span>\n          <span id=\"phone-transfer-pct\" style=\"color: var(--primary);\">0%</span>\n        </div>\n        <div style=\"font-size: 12px; color: var(--text-3); overflow: hidden; text-overflow: ellipsis; white-space: nowrap; font-family: var(--mono);\" id=\"phone-transfer-filename\">file.pdf</div>\n        <progress id=\"phone-transfer-progress\" value=\"0\" max=\"100\" style=\"display:none;\"></progress>\n        <div class=\"progress-track\">\n          <div class=\"progress-fill\" id=\"phone-transfer-bar\"></div>\n        </div>\n        <button onclick=\"phoneCancelTransfer()\" class=\"btn-cancel\">cancel transfer</button>\n      </div>\n    </div>\n\n    <!-- Screen 3: Done -->\n    <div id=\"phone-screen-done\" style=\"display: none; flex-direction: column; align-items: center; text-align: center; gap: 16px; padding: 20px 0;\">\n      <div class=\"done-icon\">✓</div>\n      <div>\n        <p id=\"phone-done-message\">TRANSFER COMPLETED!</p>\n        <p id=\"phone-done-subtext\">File.pdf</p>\n      </div>\n      <button class=\"btn-reset\" onclick=\"phoneResetToConnected()\">Transfer Another</button>\n    </div>\n  </div>\n\n  <script>\n    const isFileOrLocal = window.location.protocol === 'file:';\n    const WORKER_URL = window.LABBRIDGE_WORKER_URL || (isFileOrLocal ? 'ws://localhost:8787' : `${window.location.protocol === 'https:' ? 'wss:' : 'ws:'}//${window.location.host}`);\n    const HTTP_URL = WORKER_URL.replace('ws://', 'http://').replace('wss://', 'https://');\n\n    const state = {\n      sessionId: null,\n      ws: null,\n      cryptoKey: null,\n      folderTree: [],\n      currentFolderId: null,\n      currentFolderPath: [],\n      phase: 'waiting',\n      timerInterval: null,\n      expirySeconds: 240,\n      connectedDevice: null,\n      currentTransfer: null,\n      sendQueue: [],\n      receivedFiles: []\n    };\n\n    const PHONE_MODE = new URLSearchParams(window.location.search).get('mode') === 'phone'\n      || (navigator.maxTouchPoints > 1 && window.innerWidth <= 768);\n\n    if (PHONE_MODE) {\n      document.title = 'LabBridge — Phone';\n      window.addEventListener('DOMContentLoaded', initPhoneMode);\n    } else {\n      window.addEventListener('DOMContentLoaded', initPCMode);\n    }\n\n    function initPCMode() {\n      const pcEl = document.getElementById('pc-mode-container');\n      const phoneEl = document.getElementById('phone-mode-container');\n      if (pcEl) pcEl.style.display = 'flex';\n      if (phoneEl) phoneEl.style.display = 'none';\n      createSession();\n      setupDropzone();\n    }\n\n    function escapeHtml(str) {\n      const div = document.createElement('div');\n      div.textContent = str || '';\n      return div.innerHTML;\n    }\n\n    function flattenTreeList(tree, parentId = null) {\n      let result = [];\n      if (!tree || !Array.isArray(tree)) return result;\n      for (const item of tree) {\n        const flatItem = {\n          id: item.id,\n          name: item.name || 'Folder',\n          parentId: item.parentId || item.parent_id || parentId,\n          color: item.color || '#6C63FF'\n        };\n        result.push(flatItem);\n        if (item.children && Array.isArray(item.children)) {\n          result = result.concat(flattenTreeList(item.children, item.id));\n        }\n      }\n      return result;\n    }\n\n    async function createSession() {\n      clearInterval(state.timerInterval);\n      if (state.ws) {\n        const oldWs = state.ws;\n        state.ws = null;\n        oldWs.onclose = null;\n        if (oldWs.readyState === WebSocket.OPEN && state.phase !== 'waiting') {\n          try { oldWs.send(JSON.stringify({ type: 'cancelled' })); } catch (e) {}\n        }\n        try { oldWs.close(); } catch (e) {}\n      }\n      if (state.receivedFiles) {\n        state.receivedFiles.forEach(f => f.blobUrl && URL.revokeObjectURL(f.blobUrl));\n      }\n      state.expirySeconds = 240;\n      state.sendQueue = [];\n      state.receivedFiles = [];\n      state.currentTransfer = null;\n      setPhase('waiting');\n      \n      const overlay = document.getElementById('qr-expired-overlay');\n      if (overlay) overlay.style.display = 'none';\n      const qrcodeEl = document.getElementById('qrcode');\n      if (qrcodeEl) qrcodeEl.style.opacity = '1';\n      \n      updateTimerDisplay();\n\n      try {\n        const res = await fetch(`${HTTP_URL}/session/new`);\n        const data = await res.json();\n        state.sessionId = data.session_id;\n        const dispEl = document.getElementById('display-session-id');\n        if (dispEl) dispEl.innerText = data.session_id;\n\n        if (data.expires_at) {\n          state.expirySeconds = Math.max(0, Math.floor((new Date(data.expires_at).getTime() - Date.now()) / 1000));\n        } else {\n          state.expirySeconds = 240;\n        }\n        updateTimerDisplay();\n\n        const qrEl = document.getElementById('qrcode');\n        qrEl.innerHTML = '';\n        const expiryMs = data.expires_at ? new Date(data.expires_at).getTime() : Date.now() + 240000;\n        const pwaBase = HTTP_URL.replace('ws://', 'http://').replace('wss://', 'https://');\n        const qrPayload = `${pwaBase}/phone.html?s=${data.session_id}&e=${expiryMs}`;\n\n        new QRCode(qrEl, {\n          text: qrPayload,\n          width: 200,\n          height: 200,\n          colorDark: \"#000000\",\n          colorLight: \"#FFFFFF\",\n          correctLevel: QRCode.CorrectLevel.M\n        });\n\n        state.timerInterval = setInterval(() => {\n          state.expirySeconds--;\n          updateTimerDisplay();\n          if (state.expirySeconds <= 0) {\n            clearInterval(state.timerInterval);\n            if (state.ws) {\n              const oldWs = state.ws;\n              state.ws = null;\n              oldWs.onclose = null;\n              try { oldWs.close(); } catch (e) {}\n            }\n            if (state.phase === 'waiting') {\n              const overlay = document.getElementById('qr-expired-overlay');\n              if (overlay) overlay.style.display = 'flex';\n              const qEl = document.getElementById('qrcode');\n              if (qEl) qEl.style.opacity = '0.25';\n              const secEl = document.getElementById('timer-sec');\n              if (secEl) secEl.innerText = '0s';\n              setStatus(false, 'QR Code Expired');\n            } else {\n              console.warn('Session expired.');\n            }\n          }\n        }, 1000);\n\n        connectWebSocket();\n      } catch (err) {\n        setStatus(false, 'Error creating session');\n        console.error(err);\n      }\n    }\n\n    function handlePeerDisconnected() {\n      if (state.phase !== 'waiting') {\n        setStatus(false, 'Disconnected by phone');\n        document.getElementById('btn-disconnect').style.display = 'none';\n        clearInterval(state.timerInterval);\n        const oldWs = state.ws;\n        state.ws = null;\n        if (oldWs) {\n          oldWs.onclose = null;\n          try { oldWs.close(); } catch (e) {}\n        }\n        setPhase('waiting');\n        createSession();\n      }\n    }\n\n    function updateTimerDisplay() {\n      const el = document.getElementById('timer-sec');\n      if (el) el.innerText = `${state.expirySeconds}s`;\n      if (state.phase !== 'waiting' && state.connectedDevice) {\n        setStatus(true, `Connected: ${state.connectedDevice} (${state.expirySeconds}s left)`);\n      }\n    }\n\n    function connectWebSocket() {\n      if (state.ws) {\n        const old = state.ws;\n        old.onclose = null;\n        try { old.close(); } catch (e) {}\n      }\n      const ws = new WebSocket(`${WORKER_URL}/session/${state.sessionId}/pc`);\n      ws.binaryType = 'arraybuffer';\n      state.ws = ws;\n\n      ws.onopen = () => {\n        setStatus(false, 'Waiting for phone...');\n      };\n\n      ws.onmessage = async (event) => {\n        if (typeof event.data === 'string') {\n          const msg = JSON.parse(event.data);\n          handleTextMessage(msg);\n        } else {\n          let buffer = event.data;\n          if (buffer instanceof Blob) buffer = await buffer.arrayBuffer();\n          await handleIncomingBinaryChunk(buffer);\n        }\n      };\n\n      ws.onclose = () => {\n        handlePeerDisconnected();\n      };\n    }\n\n    async function handleTextMessage(msg) {\n      if (msg.type === 'waiting') {\n        setStatus(false, 'Waiting for phone...');\n      } else if (msg.type === 'paired') {\n        state.expirySeconds = 240;\n        updateTimerDisplay();\n        state.connectedDevice = msg.device || 'Phone App';\n        setStatus(true, `Connected: ${state.connectedDevice} (${state.expirySeconds}s left)`);\n        document.getElementById('btn-disconnect').style.display = 'block';\n        state.cryptoKey = await deriveAESKey(state.sessionId);\n        setPhase('paired');\n        if (msg.shortcut_mode) {\n          document.getElementById('shortcut-mode-hint').style.display = 'block';\n        }\n      } else if (msg.type === 'folders') {\n        const list = msg.folders || flattenTreeList(msg.tree || []);\n        state.folderTree = list;\n        renderFolders();\n      } else if (msg.type === 'ready') {\n        if (state.currentTransfer && state.currentTransfer.direction === 'sending') {\n          startSendingChunks();\n        }\n      } else if (msg.type === 'ack') {\n        if (state.currentTransfer && state.currentTransfer.direction === 'sending') {\n          handleAck(msg.chunk_index);\n        }\n      } else if (msg.type === 'shortcut_ack') {\n        setPhase('done');\n        document.getElementById('done-message').innerText = 'Received on iPhone!';\n        document.getElementById('done-subtext').innerText = 'File saved to iPhone Files app';\n      } else if (msg.type === 'transfer_init') {\n        state.currentTransfer = {\n          direction: 'receiving',\n          filename: msg.filename || 'received_file',\n          size: typeof msg.size === 'number' ? msg.size : 0,\n          total_chunks: typeof msg.total_chunks === 'number' ? msg.total_chunks : 0,\n          mime_type: msg.mime_type || 'application/octet-stream',\n          receivedChunks: 0,\n          chunksData: new Array(typeof msg.total_chunks === 'number' ? msg.total_chunks : 0)\n        };\n        setPhase('transferring');\n        updateProgressDisplay(state.currentTransfer.filename, state.currentTransfer.size, 0);\n        if (state.ws && state.ws.readyState === WebSocket.OPEN) {\n          state.ws.send(JSON.stringify({ type: 'ready' }));\n        }\n      } else if (msg.type === 'cancelled') {\n        alert('Transfer cancelled by phone');\n        setPhase('paired');\n      } else if (msg.type === 'disconnected') {\n        handlePeerDisconnected();\n      }\n    }\n\n    function setStatus(active, text) {\n      const dot = document.getElementById('status-dot');\n      const txt = document.getElementById('status-text');\n      if (active) dot.classList.add('active');\n      else dot.classList.remove('active');\n      txt.innerText = text;\n    }\n\n    function setPhase(phase) {\n      state.phase = phase;\n      document.getElementById('phase-waiting').style.display = (phase === 'waiting') ? 'flex' : 'none';\n      document.getElementById('phase-paired').style.display = (phase === 'paired') ? 'flex' : 'none';\n      document.getElementById('phase-transferring').style.display = (phase === 'transferring') ? 'flex' : 'none';\n      document.getElementById('phase-done').style.display = (phase === 'done') ? 'flex' : 'none';\n      if (phase === 'paired') {\n        renderFolders();\n        renderReceivedFiles();\n      }\n    }\n\n    function disconnectSession() {\n      if (state.ws) {\n        const oldWs = state.ws;\n        state.ws = null;\n        oldWs.onclose = null;\n        try { oldWs.send(JSON.stringify({ type: 'disconnected' })); } catch (e) {}\n        try { oldWs.close(); } catch (e) {}\n      }\n      clearInterval(state.timerInterval);\n      setPhase('waiting');\n      document.getElementById('btn-disconnect').style.display = 'none';\n      createSession();\n    }\n\n    function navigateRoot() {\n      state.currentFolderId = null;\n      state.currentFolderPath = [];\n      renderFolders();\n    }\n\n    function navigateIntoFolder(id, name) {\n      state.currentFolderId = id;\n      state.currentFolderPath.push({ id, name });\n      renderFolders();\n    }\n\n    function renderFolders() {\n      const bcEl = document.getElementById('breadcrumb');\n      if (!bcEl) return;\n      bcEl.innerHTML = '';\n      \n      const rootSpan = document.createElement('span');\n      rootSpan.className = 'breadcrumb-item';\n      rootSpan.textContent = 'Root';\n      rootSpan.addEventListener('click', () => navigateRoot());\n      bcEl.appendChild(rootSpan);\n\n      for (let i = 0; i < state.currentFolderPath.length; i++) {\n        const item = state.currentFolderPath[i];\n        const sepSpan = document.createElement('span');\n        sepSpan.className = 'breadcrumb-sep';\n        sepSpan.textContent = ' > ';\n        bcEl.appendChild(sepSpan);\n\n        const itemSpan = document.createElement('span');\n        itemSpan.className = 'breadcrumb-item';\n        itemSpan.textContent = item.name;\n        itemSpan.addEventListener('click', () => navigateUpTo(i));\n        bcEl.appendChild(itemSpan);\n      }\n\n      const children = (state.folderTree || []).filter(f => {\n        const pid = f.parentId !== undefined ? f.parentId : f.parent_id;\n        return pid === state.currentFolderId || (state.currentFolderId === null && !pid);\n      });\n      const gridEl = document.getElementById('folder-grid');\n      if (!gridEl) return;\n\n      if (children.length === 0) {\n        gridEl.innerHTML = `<p style=\"color: var(--text-3); font-size: 12px; align-self: center; font-family: var(--mono);\">No subfolders inside this directory</p>`;\n        return;\n      }\n\n      gridEl.innerHTML = '';\n      children.forEach(f => {\n        const btn = document.createElement('button');\n        btn.className = 'folder-btn';\n        btn.textContent = f.name || 'Folder';\n        btn.addEventListener('click', () => navigateIntoFolder(f.id, f.name || 'Folder'));\n        gridEl.appendChild(btn);\n      });\n    }\n\n    function navigateUpTo(index) {\n      if (index < 0) {\n        navigateRoot();\n        return;\n      }\n      state.currentFolderPath = state.currentFolderPath.slice(0, index + 1);\n      state.currentFolderId = state.currentFolderPath[state.currentFolderPath.length - 1].id;\n      renderFolders();\n    }\n\n    async function deriveAESKey(sessionId) {\n      const enc = new TextEncoder();\n      const baseKey = await crypto.subtle.importKey(\n        'raw', enc.encode(sessionId), { name: 'HKDF' }, false, ['deriveKey']\n      );\n      return await crypto.subtle.deriveKey(\n        {\n          name: 'HKDF',\n          hash: 'SHA-256',\n          salt: enc.encode('labbridge-v2'),\n          info: enc.encode('file-transfer')\n        },\n        baseKey,\n        { name: 'AES-GCM', length: 256 },\n        false,\n        ['encrypt', 'decrypt']\n      );\n    }\n\n    async function encryptChunk(plaintextBuffer, key, chunkIndex) {\n      const iv = new Uint8Array(12);\n      crypto.getRandomValues(iv);\n      const view = new DataView(iv.buffer);\n      view.setUint32(8, chunkIndex, false);\n\n      const ciphertext = await crypto.subtle.encrypt(\n        { name: 'AES-GCM', iv },\n        key,\n        plaintextBuffer\n      );\n\n      const combined = new Uint8Array(12 + ciphertext.byteLength);\n      combined.set(iv, 0);\n      combined.set(new Uint8Array(ciphertext), 12);\n      return combined.buffer;\n    }\n\n    async function decryptChunk(combinedBuffer, key, chunkIndex) {\n      const combined = new Uint8Array(combinedBuffer);\n      const iv = combined.slice(0, 12);\n      const view = new DataView(iv.buffer, iv.byteOffset, iv.byteLength);\n      const extractedIndex = view.getUint32(8, false);\n      const ciphertext = combined.slice(12);\n      const plaintext = await crypto.subtle.decrypt(\n        { name: 'AES-GCM', iv },\n        key,\n        ciphertext\n      );\n      return { chunkIndex: extractedIndex, plaintext };\n    }\n\n    function setupDropzone() {\n      const dz = document.getElementById('dropzone');\n      const fileInput = document.getElementById('file-input');\n\n      dz.addEventListener('dragover', (e) => { e.preventDefault(); dz.classList.add('dragover'); });\n      dz.addEventListener('dragleave', () => dz.classList.remove('dragover'));\n      dz.addEventListener('drop', (e) => {\n        e.preventDefault();\n        dz.classList.remove('dragover');\n        if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {\n          queueFiles(Array.from(e.dataTransfer.files));\n        }\n      });\n\n      fileInput.addEventListener('change', (e) => {\n        if (fileInput.files && fileInput.files.length > 0) {\n          queueFiles(Array.from(fileInput.files));\n          fileInput.value = '';\n        }\n      });\n    }\n\n    function queueFiles(files) {\n      if (state.phase !== 'paired' && state.phase !== 'transferring') return;\n      const validFiles = files.filter(f => {\n        if (f.size > 500 * 1024 * 1024) {\n          console.warn(`File ${f.name} is too large. Maximum size is 500MB.`);\n          alert(`File ${f.name} is too large. Maximum size is 500MB.`);\n          return false;\n        }\n        return true;\n      });\n      if (validFiles.length === 0) return;\n      \n      state.sendQueue.push(...validFiles);\n      if (state.phase === 'paired' && !state.currentTransfer) {\n        processNextInQueue();\n      } else {\n        updateQueueDisplay();\n      }\n    }\n\n    function updateQueueDisplay() {\n      const qs = document.getElementById('queue-status');\n      if (qs && state.sendQueue.length > 0) {\n        qs.innerText = `${state.sendQueue.length} more file(s) waiting in queue...`;\n      } else if (qs) {\n        qs.innerText = 'E2E encrypted · saves directly to phone folder';\n      }\n    }\n\n    function processNextInQueue() {\n      if (state.sendQueue.length === 0) {\n        setPhase('paired');\n        updateQueueDisplay();\n        return;\n      }\n      setPhase('paired');\n      const file = state.sendQueue.shift();\n      updateQueueDisplay();\n      initiateSendFile(file);\n    }\n\n    function initiateSendFile(file) {\n      if (state.phase !== 'paired' && state.phase !== 'transferring') return;\n      const totalChunks = Math.max(1, Math.ceil(file.size / (512 * 1024)));\n      \n      state.currentTransfer = {\n        direction: 'sending',\n        file: file,\n        filename: file.name,\n        size: file.size,\n        total_chunks: totalChunks,\n        sentChunks: 0,\n        pendingAck: null\n      };\n\n      setPhase('transferring');\n      updateProgressDisplay(file.name, file.size, 0);\n\n      state.ws.send(JSON.stringify({\n        type: 'transfer_init',\n        filename: file.name,\n        size: file.size,\n        total_chunks: totalChunks,\n        folder_id: state.currentFolderId,\n        mime_type: file.type || 'application/octet-stream'\n      }));\n    }\n\n    async function startSendingChunks() {\n      if (!state.currentTransfer || state.currentTransfer.direction !== 'sending') return;\n      sendNextChunk(0);\n    }\n\n    async function sendNextChunk(chunkIndex) {\n      const transfer = state.currentTransfer;\n      if (!transfer || chunkIndex >= transfer.total_chunks) {\n        state.currentTransfer = null;\n        if (state.sendQueue.length > 0) {\n          processNextInQueue();\n        } else {\n          setPhase('paired');\n          updateQueueDisplay();\n          setStatus(true, `Connected: ${state.connectedDevice} (Last sent: ${transfer ? transfer.filename : 'file'})`);\n        }\n        return;\n      }\n\n      const offset = chunkIndex * 512 * 1024;\n      const slice = transfer.file.slice(offset, offset + 512 * 1024);\n      const arrayBuffer = await slice.arrayBuffer();\n\n      const encrypted = await encryptChunk(arrayBuffer, state.cryptoKey, chunkIndex);\n      transfer.pendingAck = chunkIndex;\n      if (state.ws && state.ws.readyState === WebSocket.OPEN) {\n        state.ws.send(encrypted);\n      }\n    }\n\n    function handleAck(chunkIndex) {\n      const transfer = state.currentTransfer;\n      if (!transfer || transfer.direction !== 'sending') return;\n      \n      state.expirySeconds = 240;\n      updateTimerDisplay();\n\n      transfer.sentChunks++;\n      const pct = Math.round((transfer.sentChunks / transfer.total_chunks) * 100);\n      updateProgressDisplay(transfer.filename, transfer.size, pct);\n\n      sendNextChunk(chunkIndex + 1);\n    }\n\n    async function handleIncomingBinaryChunk(buffer) {\n      const transfer = state.currentTransfer;\n      if (!transfer || transfer.direction !== 'receiving') return;\n\n      state.expirySeconds = 240;\n      updateTimerDisplay();\n\n      try {\n        const result = await decryptChunk(buffer, state.cryptoKey, transfer.receivedChunks);\n        const idx = typeof result.chunkIndex === 'number' ? result.chunkIndex : transfer.receivedChunks;\n        transfer.chunksData[idx] = new Blob([result.plaintext]);\n        \n        let receivedCount = 0;\n        for (let i = 0; i < transfer.total_chunks; i++) {\n          if (transfer.chunksData[i] != null) receivedCount++;\n        }\n        transfer.receivedChunks = receivedCount;\n\n        const pct = Math.round((receivedCount / transfer.total_chunks) * 100);\n        updateProgressDisplay(transfer.filename, transfer.size, pct);\n\n        if (state.ws && state.ws.readyState === WebSocket.OPEN) {\n          state.ws.send(JSON.stringify({ type: 'ack', chunk_index: idx }));\n        }\n\n        if (receivedCount >= transfer.total_chunks) {\n          const finalBlob = new Blob(transfer.chunksData, { type: transfer.mime_type });\n          transfer.chunksData = null;\n          const blobUrl = URL.createObjectURL(finalBlob);\n          state.receivedFiles = state.receivedFiles || [];\n          state.receivedFiles.push({\n            filename: transfer.filename,\n            size: transfer.size,\n            mimeType: transfer.mime_type,\n            blobUrl: blobUrl\n          });\n          renderReceivedFiles();\n\n          try {\n            const a = document.createElement('a');\n            a.href = blobUrl;\n            a.download = transfer.filename;\n            document.body.appendChild(a);\n            a.click();\n            document.body.removeChild(a);\n          } catch (e) {}\n\n          state.currentTransfer = null;\n          if (state.sendQueue.length > 0) {\n            processNextInQueue();\n          } else {\n            setPhase('paired');\n            updateQueueDisplay();\n            setStatus(true, `Connected: ${state.connectedDevice} (Received: ${transfer.filename})`);\n            const sec = document.getElementById('received-files-section');\n            if (sec) sec.scrollIntoView({ behavior: 'smooth', block: 'start' });\n          }\n        }\n      } catch (err) {\n        console.error('Failed to decrypt incoming chunk:', err);\n        if (state.ws && state.ws.readyState === WebSocket.OPEN) {\n          state.ws.send(JSON.stringify({ type: 'ack', chunk_index: transfer.receivedChunks }));\n        }\n      }\n    }\n\n    function renderReceivedFiles() {\n      const section = document.getElementById('received-files-section');\n      const list = document.getElementById('received-files-list');\n      if (!section || !list) return;\n      if (!state.receivedFiles || state.receivedFiles.length === 0) {\n        section.style.display = 'none';\n        return;\n      }\n      section.style.display = 'block';\n      list.innerHTML = '';\n      state.receivedFiles.forEach(f => {\n        const item = document.createElement('div');\n        item.className = 'received-item';\n        item.style.cssText = 'padding: 14px; background: rgba(255, 255, 255, 0.03); border: 1px solid var(--border); border-radius: 10px; margin-top: 10px; font-family: var(--mono);';\n\n        const isImage = (f.mimeType && f.mimeType.startsWith('image/')) || f.filename.match(/\\.(jpg|jpeg|png|gif|webp|heic|bmp)$/i);\n        let imgHtml = '';\n        if (isImage) {\n          imgHtml = `<div style=\"margin-bottom: 12px; text-align: center; background: rgba(0,0,0,0.3); padding: 8px; border-radius: 8px;\">\n            <img src=\"${f.blobUrl}\" alt=\"${f.filename}\" style=\"max-height: 240px; max-width: 100%; border-radius: 6px; object-fit: contain;\" />\n          </div>`;\n        }\n\n        item.innerHTML = `\n          ${imgHtml}\n          <div style=\"display: flex; justify-content: space-between; align-items: center; gap: 12px; flex-wrap: wrap;\">\n            <div style=\"overflow: hidden; text-overflow: ellipsis; white-space: nowrap; flex: 1;\">\n              <strong style=\"font-size: 13px; color: #fff;\">${f.filename}</strong><br />\n              <span style=\"font-size: 11px; color: var(--text-3);\">${formatSize(f.size)}</span>\n            </div>\n            <div style=\"display: flex; gap: 8px;\">\n              <a href=\"${f.blobUrl}\" target=\"_blank\" style=\"background: transparent; border: 1px solid var(--border); color: white; text-decoration: none; padding: 7px 12px; border-radius: 6px; font-size: 12px; font-weight: 600; white-space: nowrap;\">Preview</a>\n              <a href=\"${f.blobUrl}\" download=\"${f.filename}\" style=\"background: var(--primary); color: white; text-decoration: none; padding: 7px 14px; border-radius: 6px; font-size: 12px; font-weight: 700; white-space: nowrap;\">Download</a>\n            </div>\n          </div>\n        `;\n        list.appendChild(item);\n      });\n    }\n\n    function cancelTransfer() {\n      if (state.ws && state.ws.readyState === WebSocket.OPEN) {\n        state.ws.send(JSON.stringify({ type: 'cancelled' }));\n      }\n      resetToPaired();\n    }\n\n    function resetToPaired() {\n      state.currentTransfer = null;\n      if (state.sendQueue.length > 0) {\n        processNextInQueue();\n      } else {\n        setPhase('paired');\n        updateQueueDisplay();\n      }\n    }\n\n    function updateProgressDisplay(filename, size, pct) {\n      document.getElementById('transfer-filename').innerText = filename;\n      document.getElementById('transfer-size').innerText = formatSize(size);\n      document.getElementById('transfer-pct').innerText = `${pct}%`;\n      const prog = document.getElementById('transfer-progress');\n      if (prog) prog.value = pct;\n      const fillBar = document.getElementById('progress-fill-bar');\n      if (fillBar) fillBar.style.width = pct + '%';\n    }\n\n    function formatSize(bytes) {\n      if (bytes < 1024) return bytes + ' B';\n      if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';\n      return (bytes / (1024 * 1024)).toFixed(2) + ' MB';\n    }\n\n    const phoneState = {\n      sessionId: null,\n      ws: null,\n      cryptoKey: null,\n      currentTransfer: null,\n      sendQueue: [],\n      receivedFiles: [],\n      videoStream: null,\n      scanFrameId: null\n    };\n\n    function initPhoneMode() {\n      const pcEl = document.getElementById('pc-mode-container');\n      const phoneEl = document.getElementById('phone-mode-container');\n      if (pcEl) pcEl.style.display = 'none';\n      if (phoneEl) phoneEl.style.display = 'flex';\n\n      const params = new URLSearchParams(window.location.search);\n      const s = params.get('s');\n      const e = params.get('e');\n      if (s && /^[a-zA-Z0-9]{12}$/.test(s)) {\n        if (e && parseInt(e, 10) < Date.now()) {\n          alert(\"QR/Link expired. Please scan a fresh QR code from PC.\");\n          phoneShowScreen('scanner');\n          phoneStartCamera();\n          return;\n        }\n        phoneProceedToConnected(s);\n      } else {\n        phoneShowScreen('scanner');\n        phoneStartCamera();\n      }\n    }\n\n    function phoneShowScreen(screenName) {\n      const sc = document.getElementById('phone-screen-scanner');\n      const co = document.getElementById('phone-screen-connected');\n      const dn = document.getElementById('phone-screen-done');\n      if (sc) sc.style.display = (screenName === 'scanner') ? 'flex' : 'none';\n      if (co) co.style.display = (screenName === 'connected') ? 'flex' : 'none';\n      if (dn) dn.style.display = (screenName === 'done') ? 'flex' : 'none';\n    }\n\n    async function phoneStartCamera() {\n      const video = document.getElementById('phone-video');\n      const msg = document.getElementById('phone-camera-msg');\n      if (msg) msg.style.display = 'block';\n      try {\n        phoneState.videoStream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });\n        if (video) {\n          video.srcObject = phoneState.videoStream;\n          video.setAttribute('playsinline', true);\n          video.play();\n          if (msg) msg.style.display = 'none';\n          phoneState.scanFrameId = requestAnimationFrame(phoneScanLoop);\n        }\n      } catch (err) {\n        console.warn(\"Camera permission blocked or unavailable:\", err);\n        if (msg) msg.innerText = \"Camera access denied. Please enter the 12-character ID manually above.\";\n      }\n    }\n\n    function phoneStopCamera() {\n      if (phoneState.scanFrameId) {\n        cancelAnimationFrame(phoneState.scanFrameId);\n        phoneState.scanFrameId = null;\n      }\n      if (phoneState.videoStream) {\n        phoneState.videoStream.getTracks().forEach(track => track.stop());\n        phoneState.videoStream = null;\n      }\n    }\n\n    function phoneScanLoop() {\n      const video = document.getElementById('phone-video');\n      if (!video || video.readyState !== video.HAVE_ENOUGH_DATA) {\n        phoneState.scanFrameId = requestAnimationFrame(phoneScanLoop);\n        return;\n      }\n      const canvas = document.createElement('canvas');\n      canvas.width = video.videoWidth;\n      canvas.height = video.videoHeight;\n      const ctx = canvas.getContext('2d');\n      ctx.drawImage(video, 0, 0, canvas.width, canvas.height);\n      const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);\n      const code = jsQR(imageData.data, imageData.width, imageData.height, { inversionAttempts: \"dontInvert\" });\n\n      if (code && code.data) {\n        let sessionId = null;\n        try {\n          const parsed = JSON.parse(code.data);\n          if (parsed && parsed.s) {\n            if (parsed.e && parsed.e < Date.now()) {\n              alert(\"QR code expired. Please refresh the PC screen.\");\n              phoneState.scanFrameId = requestAnimationFrame(phoneScanLoop);\n              return;\n            }\n            sessionId = parsed.s;\n          }\n        } catch (e) {\n          try {\n            const url = new URL(code.data);\n            const sParam = url.searchParams.get('s');\n            const eParam = url.searchParams.get('e');\n            if (sParam) {\n              if (eParam && parseInt(eParam, 10) < Date.now()) {\n                alert(\"QR code expired. Please refresh the PC screen.\");\n                phoneState.scanFrameId = requestAnimationFrame(phoneScanLoop);\n                return;\n              }\n              sessionId = sParam;\n            }\n          } catch (e2) {\n            if (/^[a-zA-Z0-9]{12}$/.test(code.data.trim())) {\n              sessionId = code.data.trim();\n            }\n          }\n        }\n\n        if (sessionId) {\n          phoneStopCamera();\n          phoneProceedToConnected(sessionId);\n          return;\n        }\n      }\n      phoneState.scanFrameId = requestAnimationFrame(phoneScanLoop);\n    }\n\n    function phoneConnectManual() {\n      const input = document.getElementById('phone-manual-id');\n      if (!input) return;\n      const val = input.value.trim();\n      if (!/^[a-zA-Z0-9]{12}$/.test(val)) {\n        alert(\"Please enter a valid 12-character Session ID\");\n        return;\n      }\n      phoneStopCamera();\n      phoneProceedToConnected(val);\n    }\n\n    async function phoneProceedToConnected(sessionId) {\n      phoneState.sessionId = sessionId;\n      phoneShowScreen('connected');\n      const infoEl = document.getElementById('phone-session-info');\n      if (infoEl) infoEl.innerText = `Session ID: ${sessionId}`;\n      phoneSetStatus(false, 'Connecting to PC...');\n\n      try {\n        phoneState.cryptoKey = await deriveAESKey(sessionId);\n      } catch (e) {\n        console.error(\"Failed to derive encryption key on phone:\", e);\n      }\n\n      if (phoneState.ws) {\n        const old = phoneState.ws;\n        old.onclose = null;\n        try { old.close(); } catch (e) {}\n      }\n\n      const proto = window.location.protocol === 'http:' ? 'ws:' : 'wss:';\n      const wsUrl = `${proto}//${window.location.host}/session/${sessionId}/phone`;\n      const ws = new WebSocket(wsUrl);\n      ws.binaryType = 'arraybuffer';\n      phoneState.ws = ws;\n\n      ws.onopen = () => {\n        phoneSetStatus(true, 'Connected to PC');\n      };\n\n      ws.onmessage = async (event) => {\n        if (typeof event.data === 'string') {\n          const msg = JSON.parse(event.data);\n          phoneHandleTextMessage(msg);\n        } else {\n          let buffer = event.data;\n          if (buffer instanceof Blob) buffer = await buffer.arrayBuffer();\n          await phoneHandleIncomingBinaryChunk(buffer);\n        }\n      };\n\n      ws.onclose = () => {\n        phoneSetStatus(false, 'Disconnected');\n      };\n    }\n\n    function phoneSetStatus(active, text) {\n      const dot = document.getElementById('phone-status-dot');\n      const txt = document.getElementById('phone-status-text');\n      if (dot) {\n        if (active) dot.classList.add('active');\n        else dot.classList.remove('active');\n      }\n      if (txt) txt.innerText = text;\n    }\n\n    function phoneHandleTextMessage(msg) {\n      if (msg.type === 'paired') {\n        phoneSetStatus(true, 'Connected to PC');\n      } else if (msg.type === 'ready') {\n        if (phoneState.currentTransfer && phoneState.currentTransfer.direction === 'sending') {\n          phoneStartSendingChunks();\n        }\n      } else if (msg.type === 'ack') {\n        if (phoneState.currentTransfer && phoneState.currentTransfer.direction === 'sending') {\n          phoneHandleAck(msg.chunk_index);\n        }\n      } else if (msg.type === 'transfer_init') {\n        phoneState.currentTransfer = {\n          direction: 'receiving',\n          filename: msg.filename || 'received_file',\n          size: typeof msg.size === 'number' ? msg.size : 0,\n          total_chunks: typeof msg.total_chunks === 'number' ? msg.total_chunks : 0,\n          mime_type: msg.mime_type || 'application/octet-stream',\n          receivedChunks: 0,\n          chunksData: new Array(typeof msg.total_chunks === 'number' ? msg.total_chunks : 0)\n        };\n        document.getElementById('phone-transfer-area').style.display = 'flex';\n        document.getElementById('phone-dropzone').style.display = 'none';\n        phoneUpdateProgressDisplay(phoneState.currentTransfer.filename, phoneState.currentTransfer.size, 0);\n        if (phoneState.ws && phoneState.ws.readyState === WebSocket.OPEN) {\n          phoneState.ws.send(JSON.stringify({ type: 'ready' }));\n        }\n      } else if (msg.type === 'cancelled') {\n        alert('Transfer cancelled by PC');\n        phoneResetToConnected();\n      }\n    }\n\n    async function phoneHandleIncomingBinaryChunk(buffer) {\n      const transfer = phoneState.currentTransfer;\n      if (!transfer || transfer.direction !== 'receiving') return;\n\n      try {\n        const result = await decryptChunk(buffer, phoneState.cryptoKey, transfer.receivedChunks);\n        const idx = typeof result.chunkIndex === 'number' ? result.chunkIndex : transfer.receivedChunks;\n        transfer.chunksData[idx] = new Blob([result.plaintext]);\n        \n        let receivedCount = 0;\n        for (let i = 0; i < transfer.total_chunks; i++) {\n          if (transfer.chunksData[i] != null) receivedCount++;\n        }\n        transfer.receivedChunks = receivedCount;\n\n        const pct = Math.round((receivedCount / transfer.total_chunks) * 100);\n        phoneUpdateProgressDisplay(transfer.filename, transfer.size, pct);\n\n        if (phoneState.ws && phoneState.ws.readyState === WebSocket.OPEN) {\n          state.ws.send(JSON.stringify({ type: 'ack', chunk_index: idx }));\n        }\n\n        if (receivedCount >= transfer.total_chunks) {\n          const finalBlob = new Blob(transfer.chunksData, { type: transfer.mime_type });\n          transfer.chunksData = null;\n          const blobUrl = URL.createObjectURL(finalBlob);\n\n          try {\n            const a = document.createElement('a');\n            a.href = blobUrl;\n            a.download = transfer.filename;\n            document.body.appendChild(a);\n            a.click();\n            document.body.removeChild(a);\n          } catch (e) {}\n\n          phoneState.currentTransfer = null;\n          phoneShowScreen('done');\n          document.getElementById('phone-done-message').innerText = 'Received from PC!';\n          document.getElementById('phone-done-subtext').innerText = transfer.filename;\n        }\n      } catch (err) {\n        console.error('Failed to decrypt incoming chunk on phone:', err);\n        if (phoneState.ws && phoneState.ws.readyState === WebSocket.OPEN) {\n          phoneState.ws.send(JSON.stringify({ type: 'ack', chunk_index: transfer.receivedChunks }));\n        }\n      }\n    }\n\n    function phoneHandleFilesSelected(event) {\n      const files = event.target.files ? Array.from(event.target.files) : [];\n      if (files.length === 0) return;\n      phoneState.sendQueue.push(...files);\n      event.target.value = '';\n      if (!phoneState.currentTransfer) {\n        phoneProcessNextInQueue();\n      }\n    }\n\n    function phoneProcessNextInQueue() {\n      if (phoneState.sendQueue.length === 0) {\n        phoneResetToConnected();\n        return;\n      }\n      const file = phoneState.sendQueue.shift();\n      phoneInitiateSendFile(file);\n    }\n\n    function phoneInitiateSendFile(file) {\n      const totalChunks = Math.max(1, Math.ceil(file.size / (512 * 1024)));\n      phoneState.currentTransfer = {\n        direction: 'sending',\n        file: file,\n        filename: file.name,\n        size: file.size,\n        total_chunks: totalChunks,\n        sentChunks: 0\n      };\n\n      document.getElementById('phone-dropzone').style.display = 'none';\n      document.getElementById('phone-transfer-area').style.display = 'flex';\n      phoneUpdateProgressDisplay(file.name, file.size, 0);\n\n      if (phoneState.ws && phoneState.ws.readyState === WebSocket.OPEN) {\n        phoneState.ws.send(JSON.stringify({\n          type: 'transfer_init',\n          filename: file.name,\n          size: file.size,\n          total_chunks: totalChunks,\n          mime_type: file.type || 'application/octet-stream'\n        }));\n      }\n    }\n\n    async function phoneStartSendingChunks() {\n      if (!phoneState.currentTransfer || phoneState.currentTransfer.direction !== 'sending') return;\n      phoneSendNextChunk(0);\n    }\n\n    async function phoneSendNextChunk(chunkIndex) {\n      const transfer = phoneState.currentTransfer;\n      if (!transfer || chunkIndex >= transfer.total_chunks) {\n        phoneState.currentTransfer = null;\n        if (phoneState.sendQueue.length > 0) {\n          phoneProcessNextInQueue();\n        } else {\n          phoneShowScreen('done');\n          document.getElementById('phone-done-message').innerText = 'Sent to PC!';\n          document.getElementById('phone-done-subtext').innerText = transfer ? transfer.filename : 'File sent';\n        }\n        return;\n      }\n\n      const offset = chunkIndex * 512 * 1024;\n      const slice = transfer.file.slice(offset, offset + 512 * 1024);\n      const arrayBuffer = await slice.arrayBuffer();\n\n      const encrypted = await encryptChunk(arrayBuffer, phoneState.cryptoKey, chunkIndex);\n      if (phoneState.ws && phoneState.ws.readyState === WebSocket.OPEN) {\n        phoneState.ws.send(encrypted);\n      }\n    }\n\n    function phoneHandleAck(chunkIndex) {\n      const transfer = phoneState.currentTransfer;\n      if (!transfer || transfer.direction !== 'sending') return;\n\n      transfer.sentChunks++;\n      const pct = Math.round((transfer.sentChunks / transfer.total_chunks) * 100);\n      phoneUpdateProgressDisplay(transfer.filename, transfer.size, pct);\n\n      phoneSendNextChunk(chunkIndex + 1);\n    }\n\n    function phoneCancelTransfer() {\n      if (phoneState.ws && phoneState.ws.readyState === WebSocket.OPEN) {\n        phoneState.ws.send(JSON.stringify({ type: 'cancelled' }));\n      }\n      phoneResetToConnected();\n    }\n\n    function phoneResetToConnected() {\n      phoneState.currentTransfer = null;\n      if (phoneState.sendQueue.length > 0) {\n        phoneProcessNextInQueue();\n      } else {\n        phoneShowScreen('connected');\n        document.getElementById('phone-dropzone').style.display = 'flex';\n        document.getElementById('phone-transfer-area').style.display = 'none';\n      }\n    }\n\n    function phoneUpdateProgressDisplay(filename, size, pct) {\n      const title = document.getElementById('phone-transfer-title');\n      const nameEl = document.getElementById('phone-transfer-filename');\n      const pctEl = document.getElementById('phone-transfer-pct');\n      const progEl = document.getElementById('phone-transfer-progress');\n      if (title) title.innerText = (phoneState.currentTransfer && phoneState.currentTransfer.direction === 'sending') ? 'Sending to PC...' : 'Receiving from PC...';\n      if (nameEl) nameEl.innerText = filename;\n      if (pctEl) pctEl.innerText = `${pct}%`;\n      if (progEl) progEl.value = pct;\n      const phoneFill = document.getElementById('phone-transfer-bar');\n      if (phoneFill) phoneFill.style.width = pct + '%';\n    }\n  </script>\n</body>\n</html>\n";
